import{c as e,Q as a,j as r,m as n}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"031-gui-native-app-2 · 原生应用","description":"","frontmatter":{"title":"031-gui-native-app-2 · 原生应用"},"headers":[],"relativePath":"hands-on/031-gui-native-app-2.md","filePath":"hands-on/031-gui-native-app-2.md","lastUpdated":1779686691000}'),o={name:"hands-on/031-gui-native-app-2.md"};function s(l,t,i,d,p,h){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="_031-2-terminal-文本终端组件-—-在-gui-窗口中渲染文字" tabindex="-1">031-2: Terminal 文本终端组件 — 在 GUI 窗口中渲染文字 <a class="header-anchor" href="#_031-2-terminal-文本终端组件-—-在-gui-窗口中渲染文字" aria-label="Permalink to &quot;031-2: Terminal 文本终端组件 — 在 GUI 窗口中渲染文字&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们搭好了管道 IPC 的基础设施——环形缓冲区、VFS 适配器、sys_pipe 系统调用，整个管道通道已经畅通无阻。现在我们需要一个东西来坐在管道的末端——一个能接收字节流、把它们变成屏幕上可见文字的终端组件。这就是 Terminal，一个继承自 Window 的 GUI 组件，内部维护着一个 80x25 的字符缓冲区，支持光标移动、滚动、退格、制表符，以及基本的 ANSI 转义序列。它还会通过管道把键盘输入转发给 shell 进程，并从管道中读取 shell 的输出显示到屏幕上。</p><p>完成这一章后，我们将拥有一个功能完整的文本终端组件，可以嵌入到 GUI 窗口系统中，作为 shell 进程的输入输出界面。这个组件是连接管道 IPC 和 GUI 窗口管理器的关键桥梁——没有它，管道里的数据无处可去，窗口管理器也只是一个画静态内容的框架。</p><p>前置要求：理解上一章的 Pipe IPC 机制（特别是 try_read/try_write 非阻塞接口），以及 tag 030 中 Window 类的基本接口（canvas、on_paint、on_key 等虚方法）。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="终端模拟器" tabindex="-1">终端模拟器 <a class="header-anchor" href="#终端模拟器" aria-label="Permalink to &quot;终端模拟器&quot;">​</a></h3><p>在 Unix 的世界里，终端（terminal）最早是物理设备——一个带键盘和 CRT 显示器的硬件盒子，通过串口线连到主机。DEC VT100 是 1978 年推出的经典终端，它定义了一套控制序列（后来成为 ANSI X3.64 标准的基础），至今几乎所有终端模拟器都在使用。现代操作系统里不再用物理终端了，取而代之的是终端模拟器（terminal emulator），一个在图形界面中模拟物理终端行为的软件。</p><p>终端模拟器的核心是一个二维字符网格（比如 80 列 x 25 行），每个格子存一个字符加上前景色和背景色。当有新字符到来时，终端把它写到当前光标位置，然后光标右移。到了行末就换到下一行开头。到了屏幕底部就向上滚动——把所有行往上移一行，最底下一行清空，光标回到最后一行开头。这个行为在过去四十年里几乎没有变化，xterm、gnome-terminal、Konsole 的核心逻辑都是一样的。</p><h3 id="ansi-转义序列" tabindex="-1">ANSI 转义序列 <a class="header-anchor" href="#ansi-转义序列" aria-label="Permalink to &quot;ANSI 转义序列&quot;">​</a></h3><p>光有字符显示还不够——很多程序需要清屏、移动光标、改变颜色等控制操作。这些是通过 ANSI 转义序列（也叫 escape sequence）实现的。转义序列以 ESC 字符（0x1B，也写作 <code>\\033</code>）开头，后面跟着方括号 <code>[</code> 和参数，最后以一个字母结尾。比如 <code>ESC[2J</code> 表示清屏（2 是参数表示&quot;整个屏幕&quot;，J 是命令表示&quot;擦除显示&quot;），<code>ESC[H</code> 表示把光标移到左上角（默认参数是 1,1），<code>ESC[K</code> 表示从光标位置清除到行末。</p><p>我们的 shell 输出里经常会包含这些序列——比如 shell 的 clear 命令会发送 <code>ESC[2J</code> 加 <code>ESC[H</code>，提示符刷新时可能发送 <code>ESC[K</code> 清除旧行的残留内容。如果终端组件不能正确解析这些序列，屏幕上就会出现一堆乱码一样的 <code>ESC[...</code> 字符。所以 ANSI 转义序列支持不是可选的，是终端能正常工作的必要条件。</p><h3 id="字符渲染管线" tabindex="-1">字符渲染管线 <a class="header-anchor" href="#字符渲染管线" aria-label="Permalink to &quot;字符渲染管线&quot;">​</a></h3><p>Terminal 组件使用 PSF（PC Screen Font）格式的位图字体来渲染字符。PSF 是 Linux 内核启动时使用的字体格式——每个字符对应一个固定大小的位图（通常是 8x16 像素），用一个字节数组表示。数组中的每个字节代表一行像素，每一位代表一个像素（1 = 前景色，0 = 背景色）。渲染时，我们遍历字符网格的每个格子，先画背景色矩形，再根据字形位图的每一位决定是否画前景色像素。</p><p>光标用一个反色块来表示——在光标位置画一个和前景色同色的矩形，如果光标位置有字符，就把字符的颜色反转（前景变背景色，背景变前景色），产生一种&quot;高亮选中&quot;的视觉效果。这和传统终端的光标外观一致，用户一眼就能看到光标在哪里。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-设计-terminalcell-和字符缓冲区" tabindex="-1">Step 1: 设计 TerminalCell 和字符缓冲区 <a class="header-anchor" href="#step-1-设计-terminalcell-和字符缓冲区" aria-label="Permalink to &quot;Step 1: 设计 TerminalCell 和字符缓冲区&quot;">​</a></h3><p><strong>目标</strong>: 定义一个结构来表示终端中的一个字符格子，并创建 80x25 的二维数组作为屏幕缓冲区。</p><p><strong>设计思路</strong>: 每个 TerminalCell 需要三个字段：字符本身（一个 char）、前景色（32 位整数，0x00RRGGBB 格式）、背景色（同样 32 位整数）。默认值是空格、白字（0x00FFFFFF）黑底（0x00000000）。选择 80x25 是因为这是 IBM PC 在 1981 年就定下来的 VGA 文本模式分辨率，几乎所有终端和 shell 都默认支持它。屏幕缓冲区是一个 80x25 的二维数组，直接嵌入 Terminal 对象中（约 24KB），不需要额外的堆分配。</p><p>Terminal 继承自 Window，在构造时根据字符网格尺寸计算窗口像素大小：宽度 = 80 * 8 = 640 像素，高度 = 25 * 16 = 400 像素。加上 Window 的 20 像素标题栏，整个窗口高度 420 像素。这个大小在 1024x768 的屏幕上既能容纳足够的文字，又不会挤占太多桌面空间。</p><p><strong>实现约束</strong>: 构造函数需要初始化所有格子为默认值（空格、白色前景、黑色背景）。Terminal 类需要提供 cell(row, col) 访问器来读取单个格子内容，以及 cursor_x()、cursor_y() 查询接口获取光标位置。窗口标题通过构造参数传入，用于在标题栏显示终端名称。Terminal 还需要重写 is_terminal() 虚方法返回 true，让窗口管理器能安全地识别终端窗口。</p><p><strong>验证</strong>: 创建 Terminal 对象后检查默认缓冲区内容——所有格子应该是空格字符、白色前景、黑色背景。检查光标初始位置应为 (0, 0)。检查窗口的像素尺寸应为 640x400。</p><h3 id="step-2-实现字符处理与光标管理" tabindex="-1">Step 2: 实现字符处理与光标管理 <a class="header-anchor" href="#step-2-实现字符处理与光标管理" aria-label="Permalink to &quot;Step 2: 实现字符处理与光标管理&quot;">​</a></h3><p><strong>目标</strong>: 实现 process_char、newline、scroll_up、backspace、tab 等核心方法，以及 write 接口来处理完整的字符串输入。</p><p><strong>设计思路</strong>: write 方法是外部写入文本的入口（shell 输出和管道数据都通过它进入终端），它遍历输入字符串的每个字符，根据字符类型分派到不同的处理逻辑。普通可打印字符走 process_char——把字符写入当前光标位置的 TerminalCell，设置前景色和背景色，然后光标右移。如果光标到了行末（第 80 列），自动换行到下一行开头。换行符走 newline——重置 cursor_x 为 0，cursor_y 加 1，如果到了屏幕底部（第 25 行）就触发 scroll_up。退格符走 backspace——光标左移一格并清空格子，处理行首时回退到上一行末尾。制表符走 tab——光标跳到下一个 8 的倍数列。</p><p><strong>实现约束</strong>: 只处理 ASCII 0x20 到 0x7E 范围内的可打印字符，其他字符的 process_char 调用不做任何事（避免把控制字符写入缓冲区）。scroll_up 一定要先把行 1 到行 24 拷贝到行 0 到行 23，然后清空行 24——顺序不能反，否则数据会被覆盖。cursor_y 的范围是 0 到 ROWS-1，当 newline 导致 cursor_y 等于 ROWS 时要回退到 ROWS-1 并触发滚动。backspace 需要处理光标在 (0, 0) 位置时什么都不做的边界情况。</p><p><strong>踩坑预警</strong>: scroll_up 的实现一定要从上往下拷贝（行 1 -&gt; 行 0，行 2 -&gt; 行 1，...），不能从下往上拷贝。如果反过来，行 1 被拷到行 0 后行 0 的原始数据就丢了，然后行 2 拷到行 1 的时候实际拷的是已经被覆盖的数据。另外，newline 中 cursor_y 的更新顺序也有讲究——先加 1，然后判断是否 &gt;= ROWS，如果是就回退到 ROWS-1 并 scroll_up。不要先 scroll_up 再加 1，否则最后一行永远不会被滚动。</p><p><strong>验证</strong>: 依次写入单个字符验证光标位置递增、写入 80 个字符验证自动换行、写入 25 行以上验证滚动行为（前 24 行被推上去，最后一行是新内容）、写入退格验证光标回退和格子清空、写入制表符验证跳到 8 的倍数列。</p><h3 id="step-3-实现-ansi-转义序列解析" tabindex="-1">Step 3: 实现 ANSI 转义序列解析 <a class="header-anchor" href="#step-3-实现-ansi-转义序列解析" aria-label="Permalink to &quot;Step 3: 实现 ANSI 转义序列解析&quot;">​</a></h3><p><strong>目标</strong>: 在 write 方法中检测 ESC 字符，解析后续的 CSI（Control Sequence Introducer）序列并执行对应操作。</p><p><strong>设计思路</strong>: write 方法在遍历字符时先检查当前字符是否是 ESC（0x1B）。如果是，进入 handle_ansi 解析流程。解析逻辑是：先期望下一个字符是 <code>[</code>（如果不是就跳过 ESC 字符继续正常处理），然后收集数字参数（0-9 的数字和分号分隔符），最后根据结尾字母（大写或小写）分派到对应操作。目前支持的命令：J（擦除显示，仅参数 == 2 时执行 clear）、H（光标归位到 0,0）、K（从光标位置清除到行末，把当前行剩余的格子重置为默认 TerminalCell）、m（SGR 颜色控制，暂时忽略不做任何事）。</p><p><strong>实现约束</strong>: handle_ansi 的 pos 参数是引用类型，函数会推进它跳过整个转义序列的所有字节。参数解析目前只收集一个数字（param 变量），多参数场景用分号分隔时只取最后一个数字的累积值——对于我们 shell 用到的序列（ESC[2J、ESC[H、ESC[K）这已经够用了。不识别的结尾字母直接 return，不做任何操作。parse 过程中遇到非数字、非分号、非字母的意外字符也直接 return。</p><p><strong>验证</strong>: 写入 &quot;helloESC[2J&quot; 验证清屏（缓冲区全部重置为空格）、写入 &quot;abcESC[H&quot; 验证光标归位到 (0, 0)、写入 &quot;helloESC[K&quot; 验证从光标位置到行末被清空、写入不完整的序列如 &quot;ESC[&quot; 或 &quot;ESC[?&quot; 验证不会崩溃。</p><h3 id="step-4-实现管道集成与键盘输入转发" tabindex="-1">Step 4: 实现管道集成与键盘输入转发 <a class="header-anchor" href="#step-4-实现管道集成与键盘输入转发" aria-label="Permalink to &quot;Step 4: 实现管道集成与键盘输入转发&quot;">​</a></h3><p><strong>目标</strong>: 让 Terminal 通过管道与 shell 进程通信——键盘输入写入 stdin 管道，shell 输出从 stdout 管道读取。</p><p><strong>设计思路</strong>: Terminal 持有两个 Pipe 指针——stdin_pipe 和 stdout_pipe。stdin_pipe 的方向是&quot;终端 -&gt; shell&quot;：on_key 收到键盘事件时，如果 stdin_pipe 已设置，就把字符通过 try_write 写入管道而不是直接显示到屏幕缓冲区。shell 进程通过 sys_read(fd=0) 从管道的另一端（PipeReadOps）读取这些字符。echo 由 shell 通过 stdout 回来。stdout_pipe 的方向是&quot;shell -&gt; 终端&quot;：shell 的 sys_write(fd=1) 通过 PipeWriteOps 写入管道，终端通过 poll_output 在 PIT tick 中调用 try_read 从管道读取数据，然后调用 write 方法显示到字符缓冲区。</p><p><strong>实现约束</strong>: on_key 只处理按下事件（pressed == true）和有 ASCII 值的按键（ascii != 0），松开事件和无 ASCII 按键（如功能键、方向键）被忽略。回车键（\\r）需要转换为换行（\\n）再写入管道——因为 shell 期望 stdin 收到换行符。poll_output 使用 try_read 而不是阻塞 read，因为在 PIT 中断上下文中绝对不能阻塞。析构函数需要关闭管道端点——stdin 关闭写端（通知 shell stdin EOF），stdout 关闭读端（让 shell 的 write 返回 -1）。</p><p><strong>验证</strong>: 设置 stdin_pipe 后，键盘输入不应该直接显示在终端上（被转发到了 shell），shell 通过 stdout 回显时才在终端出现。设置 stdout_pipe 后，通过 pipe 直接写入数据（模拟 shell 输出），调用 poll_output 后数据应该出现在终端缓冲区。</p><h3 id="step-5-实现字符渲染" tabindex="-1">Step 5: 实现字符渲染 <a class="header-anchor" href="#step-5-实现字符渲染" aria-label="Permalink to &quot;Step 5: 实现字符渲染&quot;">​</a></h3><p><strong>目标</strong>: 将字符缓冲区的内容渲染到 Window 的 Canvas 上，让文字真正显示在屏幕上。</p><p><strong>设计思路</strong>: render_to_canvas 方法遍历 80x25 的字符网格，对每个格子先画背景矩形（draw_rect），然后如果字符不是空格就从 PSF 字体中取出字形位图，按位绘制前景色像素（draw_pixel）。光标位置额外画一个反色块——先画一个和前景色同色的矩形覆盖整个字符位置，如果该位置有字符则用背景色重新画字形位图。on_paint 方法在 font 已设置的情况下直接调用 render_to_canvas。</p><p><strong>实现约束</strong>: 像素坐标的计算是（列 * 字符宽度, 标题栏高度 + 行 * 字符高度）。标题栏高度来自 Window::TITLE_BAR_HEIGHT 常量（20 像素）。渲染是在 window 的内部 Canvas 上而不是 screen canvas 上——WindowManager 的 composite 方法负责把各个窗口的 Canvas 合成到屏幕。font 为 nullptr 时 render_to_canvas 直接返回不做任何事，避免在字体未加载时访问空指针。</p><p><strong>验证</strong>: 向 Terminal 写入文字后调用 render_to_canvas，然后读取 Canvas 对应位置的像素颜色，验证背景色和前景色正确。验证光标位置有一个反色块。验证空格格子只有背景色没有前景色像素。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>确保 <code>kernel/gui/terminal.cpp</code> 和 <code>terminal.hpp</code> 已加入 GUI 模块的 CMakeLists.txt。Terminal 类只在 CINUX_GUI 宏定义时编译，不影响无 GUI 配置的构建。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>运行 QEMU，如果 GUI 启动流程中创建了 Terminal 窗口（通过 create_shell_terminal），你应该能看到一个 640x400 像素的窗口，标题栏显示终端名称（如 &quot;Shell #1&quot;），内容区域为黑色背景。如果管道已连接且有 shell 进程在运行，shell 的提示符会出现在终端窗口内，键盘输入也会被正确转发。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>终端窗口一片空白</strong>：首先检查 font 是否已通过 set_font 设置。render_to_canvas 在 font_ 为 nullptr 时直接返回不做任何渲染——这是最常见的&quot;窗口创建了但什么都没画&quot;的原因。同时检查 poll_output 是否被 PIT 回调正确调用——如果没有调用，shell 的输出就留在管道里不会被读取显示。</p><p><strong>键盘输入没有反应</strong>：确认 stdin_pipe 是否已通过 set_stdin_pipe 设置。如果管道未设置，on_key 会把字符直接写入屏幕缓冲区（不经过 shell echo），这是终端的&quot;本地编辑模式&quot;。如果管道已设置但仍然没反应，检查 try_write 的返回值——如果返回 0 说明管道的读端（shell 那边）可能还没开始读取，缓冲区满了。</p><p><strong>输出乱码或出现 ESC 字符</strong>：ANSI 解析没有正确识别转义序列。检查 handle_ansi 中对 ESC 后面 <code>[</code> 的判断是否正确——只有紧跟着 <code>[</code> 的 ESC 才会进入 CSI 解析，否则 ESC 被当作普通字符跳过。另一个常见问题是 shell 输出了我们不支持的 ANSI 序列（比如颜色控制 ESC[31m），这不会导致崩溃但可能影响后续字符的显示位置——因为 handle_ansi 会消耗掉整个序列。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>职责</th></tr></thead><tbody><tr><td>TerminalCell</td><td>单个字符格子（char + fg 色彩 + bg 色彩）</td></tr><tr><td>screen_[25][80]</td><td>80x25 字符缓冲区（约 24KB）</td></tr><tr><td>process_char</td><td>可打印字符写入 + 光标右移 + 行末自动换行</td></tr><tr><td>scroll_up</td><td>所有行上移一行 + 清空最后一行</td></tr><tr><td>newline</td><td>光标移到下一行开头 + 底部触发滚动</td></tr><tr><td>handle_ansi</td><td>解析 ESC[ CSI 序列（J 清屏、H 归位、K 清行）</td></tr><tr><td>on_key</td><td>键盘事件 -&gt; stdin 管道或直接写入缓冲区</td></tr><tr><td>poll_output</td><td>stdout 管道 try_read -&gt; write -&gt; 缓冲区</td></tr><tr><td>render_to_canvas</td><td>缓冲区逐字符 -&gt; PSF 位图 -&gt; Canvas 像素</td></tr><tr><td>is_terminal()</td><td>虚方法返回 true，供 WindowManager 安全识别</td></tr></tbody></table>',53)])])}const _=e(o,[["render",s]]);export{u as __pageData,_ as default};
